package com.trademaster.ims.mobile.payments.repository;
import com.trademaster.ims.mobile.payments.model.CustomerPayment;import jakarta.persistence.LockModeType;import org.springframework.data.jpa.repository.*;import org.springframework.data.repository.query.Param;import java.util.*;
